# Common FAANG patterns using sets
def two_sum(nums, target):
    seen = set()
    for num in nums:
        if target - num in seen: return True  # O(1) lookup
        seen.add(num)
    return False

def longest_consecutive(nums):
    num_set = set(nums)
    best = 0
    for n in num_set:
        if n - 1 not in num_set:   # start of a sequence
            length = 1
            while n + length in num_set: length += 1
            best = max(best, length)
    return best  # O(N) total — each number visited at most twice

from collections import Counter, defaultdict

# === Anagram Detection — frequency map comparison ===
def is_anagram(s, t):
    return Counter(s) == Counter(t)  # O(N)

# === Group Anagrams ===
def group_anagrams(strs):
    groups = defaultdict(list)
    for s in strs:
        key = tuple(sorted(s))   # canonical form
        groups[key].append(s)
    return list(groups.values())

# === Sliding Window with Counter ===
def find_anagrams_in_string(s, p):
    """Find all start indices of p's anagrams in s."""
    result = []
    p_count = Counter(p)
    window = Counter(s[:len(p)])
    if window == p_count: result.append(0)

    for i in range(len(p), len(s)):
        # Add new char, remove old char
        window[s[i]] += 1
        window[s[i - len(p)]] -= 1
        if window[s[i - len(p)]] == 0:
            del window[s[i - len(p)]]  # keep counter clean
        if window == p_count:
            result.append(i - len(p) + 1)
    return result

# === Top K Frequent Elements ===
def top_k_frequent(nums, k):
    # Bucket sort approach — O(N), beats heap O(N log K)
    count = Counter(nums)
    buckets = [[] for _ in range(len(nums) + 1)]
    for num, freq in count.items():
        buckets[freq].append(num)
    result = []
    for i in range(len(buckets)-1, 0, -1):
        result.extend(buckets[i])
        if len(result) >= k: break
    return result[:k]
